const _ = require('underscore');

function findUnique(arrays) {
  const set = new Set(arrays[0]);
  for (let i = 1; i < arrays.length; i++) {
    arrays[i].forEach(element => set.delete(element));
  }
  return Array.from(set);
}

// Example usage:
const arrays = [[1, 2, 3, 4, 5], [2, 4, 6, 8, 10], [1, 3, 5, 7, 9]];
console.log(findUnique(arrays)); // Output: [2, 4, 6, 8, 10]
