const crypto = require('crypto');
const randomString = require('crypto-random-string');

function pbkdf2(password, salt, iterations, keyLength, hashAlgorithm = 'sha256') {
  const algorithm = crypto.createHmac(hashAlgorithm, salt);
  let key = Buffer.alloc(0);
  let previousHash;

  for (let i = 0; i < iterations; i++) {
    if (i > 0) {
      algorithm.update(previousHash);
    }
    const hash = algorithm.digest();
    key = Buffer.concat([key, hash.slice(0, keyLength)]);
    previousHash = hash;
  }

  return key;
}

function generateSalt() {
  return randomString(16);
}

const password = 'mysecretpassword';
const salt = generateSalt();
