const camelcase = require('camelcase');
const replace = require('replace');
const split = require('split');

function convertToLowerCase(str, separator = '-') {
    const words = camelcase(str).split('');
    const newStr = words.reduce((acc, curr, index) => {
        if (index > 0 && index % 2 !== 0) {
            acc += separator;
        }
        acc += curr.toLowerCase();
        return acc;
    }, '');
    return newStr;
}

const originalStr = "helloWorld";
const newStr = convertToLowerCase(originalStr);
console.log(newStr); // Output: hello-world
